import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

import {
  buildCircuitMetadata,
  loadCatalogOverrides,
  loadComponentDefinitionLiterals,
  resolveCircuitCatalogPaths,
} from './circuit-component-metadata.shared.mjs';

function generateFileSource({ categoryOrder, categoryLabels, metadata }) {
  return [
    "import type { CircuitComponentMetadata } from '../circuitComponentCatalogTypes';",
    '',
    '// This file is generated by apps/web/scripts/generate-circuit-component-metadata.mjs.',
    '// Do not edit by hand; update componentDefinitions.ts or circuit-component-metadata.overrides.json instead.',
    '',
    `export const CIRCUIT_COMPONENT_CATEGORY_ORDER: string[] = ${JSON.stringify(categoryOrder, null, 2)};`,
    '',
    `export const CIRCUIT_COMPONENT_CATEGORY_LABELS: Record<string, string> = ${JSON.stringify(categoryLabels, null, 2)};`,
    '',
    `export const CIRCUIT_COMPONENT_METADATA: CircuitComponentMetadata[] = ${JSON.stringify(metadata, null, 2)};`,
    '',
  ].join('\n');
}

const scriptDir = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(scriptDir, '..', '..', '..');
const { definitionsPath, overridesPath, generatedPath } = resolveCircuitCatalogPaths(repoRoot);
const definitions = loadComponentDefinitionLiterals(definitionsPath);
const overrides = loadCatalogOverrides(overridesPath);
const generatedCatalog = buildCircuitMetadata(definitions, overrides);

fs.mkdirSync(path.dirname(generatedPath), { recursive: true });
fs.writeFileSync(generatedPath, generateFileSource(generatedCatalog), 'utf8');
console.log(`Generated circuit component metadata: ${path.relative(repoRoot, generatedPath)}`);
